import React from 'react';

const feedbackItems = [
  {
    quote: 'Placeholder: Add a quote from a performance review, peer feedback, or manager evaluation.',
    author: 'Placeholder Name',
    title: 'Title',
    company: 'Company',
  },
  {
    quote: 'Placeholder: Add another piece of feedback or accolade from a past role.',
    author: 'Placeholder Name',
    title: 'Title',
    company: 'Company',
  },
  {
    quote: 'Placeholder: Add a third piece of feedback highlighting a specific strength or accomplishment.',
    author: 'Placeholder Name',
    title: 'Title',
    company: 'Company',
  },
];

function Feedback() {
  return (
    <section id="feedback">
      <h2 className="section-title">Feedback &amp; Accolades</h2>
      {feedbackItems.map((item, i) => (
        <div className="feedback-item" key={i}>
          <blockquote>"{item.quote}"</blockquote>
          <div className="attribution">
            {item.author}, {item.title} &mdash;{' '}
            <span className="company">{item.company}</span>
          </div>
        </div>
      ))}
    </section>
  );
}

export default Feedback;
